import React, { useState, useMemo, useCallback } from "react";

function IndividualAnalysis({ 
  customerData, 
  onInputChange, 
  onAnalyze, 
  onReset,
  loading, 
  results 
}) {
  const [activeTab, setActiveTab] = useState("core");
  const [errors, setErrors] = useState({});

  // Input validation
  const validateField = (name, value) => {
    const newErrors = { ...errors };
    
    switch (name) {
      case 'Tenure':
        if (value < 0) newErrors[name] = 'Tenure cannot be negative';
        else delete newErrors[name];
        break;
      case 'SatisfactionScore':
        if (value < 1 || value > 5) newErrors[name] = 'Score must be between 1-5';
        else delete newErrors[name];
        break;
      case 'OrderCount':
        if (value < 0) newErrors[name] = 'Order count cannot be negative';
        else delete newErrors[name];
        break;
      case 'CashbackAmount':
        if (value < 0) newErrors[name] = 'Cashback cannot be negative';
        else delete newErrors[name];
        break;
      default:
        delete newErrors[name];
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = useCallback((e) => {
    const { name, value, type } = e.target;
    const processedValue = type === "number" ? parseFloat(value) || 0 : value;
    onInputChange({ ...customerData, [name]: processedValue });
  }, [customerData, onInputChange]);

  const handleNumberChange = useCallback((name, value) => {
    if (value === "" || value === null || value === undefined) {
      onInputChange({ ...customerData, [name]: "" });
    } else {
      const numValue = parseFloat(value);
      if (!isNaN(numValue)) {
        validateField(name, numValue);
        onInputChange({ ...customerData, [name]: numValue });
      }
    }
  }, [customerData, onInputChange]);

  const incrementValue = useCallback((name, step = 1) => {
    const currentValue = customerData[name] || 0;
    onInputChange({ ...customerData, [name]: currentValue + step });
  }, [customerData, onInputChange]);

  const decrementValue = useCallback((name, step = 1) => {
    const currentValue = customerData[name] || 0;
    const newValue = Math.max(0, currentValue - step);
    onInputChange({ ...customerData, [name]: newValue });
  }, [customerData, onInputChange]);

  const handleRangeChange = useCallback((name, value) => {
    const numValue = parseFloat(value);
    validateField(name, numValue);
    onInputChange({ ...customerData, [name]: numValue });
  }, [customerData, onInputChange]);

  const toggleComplaint = useCallback(() => {
    onInputChange({ 
      ...customerData, 
      Complain: customerData.Complain === 1 ? 0 : 1 
    });
  }, [customerData, onInputChange]);

  const handleKeyPress = useCallback((event, name, operation) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      if (operation === 'increment') {
        incrementValue(name);
      } else {
        decrementValue(name);
      }
    }
  }, [incrementValue, decrementValue]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!loading && Object.keys(errors).length === 0) {
      onAnalyze();
    }
  };

  const renderField = (label, name, type = "number", options = null, step = 1, helpText = "") => {
    // Special case for Satisfaction Score - use range slider
    if (name === "SatisfactionScore") {
      return (
        <div className="field-container">
          <div className="field-header">
            <label htmlFor={name} className="field-label">{label}</label>
            {helpText && <span className="field-help" title={helpText} aria-label={helpText}>ℹ️</span>}
          </div>
          <div className="range-slider-container">
            <input
              id={name}
              type="range"
              name={name}
              min="1"
              max="5"
              step="1"
              value={customerData[name] || 1}
              onChange={(e) => handleRangeChange(name, e.target.value)}
              className="range-slider"
              aria-valuemin="1"
              aria-valuemax="5"
              aria-valuenow={customerData[name] || 1}
              aria-valuetext={`Satisfaction score ${customerData[name] || 1} out of 5`}
            />
            <div className="range-labels">
              {[1, 2, 3, 4, 5].map(num => (
                <span 
                  key={num} 
                  className={`range-label ${(customerData[name] || 1) === num ? 'active' : ''}`}
                  onClick={() => handleRangeChange(name, num)}
                  role="button"
                  tabIndex={0}
                  onKeyPress={(e) => e.key === 'Enter' && handleRangeChange(name, num)}
                  aria-label={`Set satisfaction to ${num}`}
                >
                  {num}
                </span>
              ))}
            </div>
            <div className="range-value-display" aria-live="polite">
              <span className="range-current-value">{customerData[name] || 1}</span>
              <span className="range-max-value">/5</span>
            </div>
          </div>
          {errors[name] && <span className="field-error" role="alert">⚠️ {errors[name]}</span>}
        </div>
      );
    }

    // Special case for Complaint Filed - use simple toggle button without ON/OFF status
    if (name === "Complain") {
      return (
        <div className="field-container">
          <div className="field-header">
            <label className="field-label">{label}</label>
            {helpText && <span className="field-help" title={helpText} aria-label={helpText}>ℹ️</span>}
          </div>
          <div className="toggle-button-container">
            <button
              type="button"
              className={`simple-toggle-btn ${customerData.Complain === 1 ? 'active' : ''}`}
              onClick={toggleComplaint}
              aria-pressed={customerData.Complain === 1}
              aria-label={`Complaint filed: ${customerData.Complain === 1 ? 'Yes' : 'No'}`}
            >
              <span className="toggle-track">
                <span className="toggle-thumb"></span>
              </span>
              <span className="toggle-label">
                {customerData.Complain === 1 ? 'Complaint Filed' : 'No Complaint'}
              </span>
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="field-container">
        <div className="field-header">
          <label htmlFor={name} className="field-label">{label}</label>
          {helpText && <span className="field-help" title={helpText} aria-label={helpText}>ℹ️</span>}
        </div>
        {options ? (
          <select 
            id={name}
            name={name} 
            value={customerData[name] || ""}
            onChange={handleChange}
            className={`form-select ${errors[name] ? 'error' : ''}`}
            aria-describedby={errors[name] ? `${name}-error` : undefined}
          >
            <option value="">Select an option</option>
            {options.map((opt, i) => (
              <option key={i} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        ) : type === "number" ? (
          <div className={`number-input-wrapper ${errors[name] ? 'error' : ''}`}>
            <input 
              id={name}
              type="number"
              name={name} 
              value={customerData[name] ?? ""}
              onChange={(e) => handleNumberChange(name, e.target.value)}
              step={step}
              min="0"
              className="form-input number-input"
              placeholder="0"
              aria-describedby={errors[name] ? `${name}-error` : undefined}
            />
            <div className="number-controls">
              <button 
                type="button"
                className="number-control-btn increment"
                onClick={() => incrementValue(name, step)}
                onKeyPress={(e) => handleKeyPress(e, name, 'increment')}
                tabIndex={0}
                aria-label={`Increase ${label}`}
              >
                <span className="control-icon" aria-hidden="true"></span>
              </button>
              <button 
                type="button"
                className="number-control-btn decrement"
                onClick={() => decrementValue(name, step)}
                onKeyPress={(e) => handleKeyPress(e, name, 'decrement')}
                tabIndex={0}
                aria-label={`Decrease ${label}`}
              >
                <span className="control-icon" aria-hidden="true"></span>
              </button>
            </div>
          </div>
        ) : (
          <input 
            id={name}
            type={type} 
            name={name} 
            value={customerData[name] || ""}
            onChange={handleChange}
            className={`form-input ${errors[name] ? 'error' : ''}`}
            placeholder="Enter value"
            aria-describedby={errors[name] ? `${name}-error` : undefined}
          />
        )}
        {errors[name] && (
          <span id={`${name}-error`} className="field-error" role="alert">
            ⚠️ {errors[name]}
          </span>
        )}
      </div>
    );
  };

  // Skeleton loading component
  const ResultsSkeleton = () => (
    <div className="results-panel">
      <div className="results-header">
        <h3>📊 Analysis Results</h3>
        <div className="skeleton-text" style={{width: '150px'}}></div>
      </div>
      <div className="results-grid">
        {[1, 2, 3, 4].map(i => (
          <div key={i} className="result-card skeleton-card">
            <div className="skeleton-line" style={{width: '70%'}}></div>
            <div className="skeleton-line" style={{width: '90%'}}></div>
            <div className="skeleton-line" style={{width: '60%'}}></div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderResults = () => {
    if (loading) return <ResultsSkeleton />;
    if (!results) return null;

    const probability = results.probability !== undefined ? results.probability : 
                       results.churn_probability !== undefined ? results.churn_probability : 0;
    const prediction = results.prediction !== undefined ? results.prediction : 
                      results.churn_prediction !== undefined ? results.churn_prediction : false;

    const riskLevel = probability > 0.7 ? "high" : probability > 0.4 ? "medium" : "low";

    return (
      <div className="results-panel">
        <div className="results-header">
          <h3>📊 Analysis Results</h3>
          <div className="results-meta">
            <span className="timestamp">Generated: {new Date().toLocaleTimeString()}</span>
          </div>
        </div>

        <div className="results-grid">
          {/* Risk Assessment Card */}
          <div className="result-card risk-assessment">
            <div className="card-header">
              <h4>Risk Assessment</h4>
              <div className={`risk-badge ${riskLevel}`} aria-live="polite">
                {riskLevel.toUpperCase()} RISK
              </div>
            </div>
            <div className="probability-display">
              <div className="probability-circle">
                <div className="circle-background">
                  <div 
                    className="circle-progress" 
                    style={{ transform: `rotate(${probability * 180}deg)` }}
                  ></div>
                </div>
                <span className="probability-value">{(probability * 100).toFixed(1)}%</span>
              </div>
              <div className="probability-label">
                <span className="prediction-text">
                  {prediction ? "High Churn Probability" : "Low Churn Probability"}
                </span>
                <span className="confidence">98.2% confidence</span>
              </div>
            </div>
          </div>

          {/* Key Metrics Card */}
          <div className="result-card key-metrics">
            <h4>Key Metrics</h4>
            <div className="metrics-grid">
              <div className="metric">
                <span className="metric-value">{customerData.Tenure || 0}</span>
                <span className="metric-label">Months Tenure</span>
              </div>
              <div className="metric">
                <span className="metric-value">{customerData.OrderCount || 0}</span>
                <span className="metric-label">Total Orders</span>
              </div>
              <div className="metric">
                <span className="metric-value">{customerData.SatisfactionScore || 1}/5</span>
                <span className="metric-label">Satisfaction</span>
              </div>
              <div className="metric">
                <span className="metric-value">{customerData.Complain === 1 ? 'Yes' : 'No'}</span>
                <span className="metric-label">Complaint Filed</span>
              </div>
            </div>
          </div>

          {/* Recommendations Card */}
          <div className="result-card recommendations">
            <h4>💡 Recommendations</h4>
            <div className="recommendations-list">
              {prediction ? (
                <>
                  <div className="recommendation critical">
                    <span className="rec-icon">🚨</span>
                    <div className="rec-content">
                      <strong>Immediate Action Required</strong>
                      <p>Offer personalized retention package with enhanced benefits</p>
                    </div>
                  </div>
                  <div className="recommendation">
                    <span className="rec-icon">📞</span>
                    <div className="rec-content">
                      <strong>Proactive Outreach</strong>
                      <p>Schedule customer success call within 48 hours</p>
                    </div>
                  </div>
                </>
              ) : (
                <div className="recommendation positive">
                  <span className="rec-icon">✅</span>
                  <div className="rec-content">
                    <strong>Customer is Stable</strong>
                    <p>Continue with current engagement strategy</p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Feature Importance */}
          {results.feature_importance && (
            <div className="result-card feature-importance">
              <h4>📈 Key Influencers</h4>
              <div className="factors-list">
                {Object.entries(results.feature_importance)
                  .slice(0, 4)
                  .map(([feature, importance], index) => (
                  <div key={feature} className="factor-item">
                    <div className="factor-header">
                      <span className="factor-rank">#{index + 1}</span>
                      <span className="factor-name">
                        {feature.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())}
                      </span>
                      <span className="factor-value">{(importance * 100).toFixed(1)}%</span>
                    </div>
                    <div className="factor-bar">
                      <div 
                        className="factor-fill" 
                        style={{ width: `${(importance * 100)}%` }}
                      ></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="individual-analysis">
      {/* Single Line Header */}
      <div className="analysis-header-single">
        <h2>👤 Individual Customer Analysis</h2>
        <p className="header-subtitle">Enter customer details to predict churn probability and get actionable insights</p>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="analysis-container">
          {/* Quick Stats */}
          <div className="quick-stats">
            <div className="stat-card">
              <div className="stat-icon">📅</div>
              <div className="stat-info">
                <span className="stat-value">{customerData.Tenure || 0}</span>
                <span className="stat-label">Months Tenure</span>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">🛒</div>
              <div className="stat-info">
                <span className="stat-value">{customerData.OrderCount || 0}</span>
                <span className="stat-label">Total Orders</span>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">⭐</div>
              <div className="stat-info">
                <span className="stat-value">{customerData.SatisfactionScore || 1}/5</span>
                <span className="stat-label">Satisfaction</span>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">🚨</div>
              <div className="stat-info">
                <span className="stat-value">{customerData.Complain === 1 ? 'Yes' : 'No'}</span>
                <span className="stat-label">Complaint</span>
              </div>
            </div>
          </div>

          {/* Tabbed Interface */}
          <div className="tabbed-interface">
            <div className="tab-navigation" role="tablist" aria-label="Customer data categories">
              <button
                className={`tab-nav-btn ${activeTab === "core" ? "active" : ""}`}
                onClick={() => setActiveTab("core")}
                role="tab"
                aria-selected={activeTab === "core"}
                aria-controls="core-panel"
                id="core-tab"
              >
                <span className="tab-icon">💰</span>
                Core Metrics
              </button>
              <button
                className={`tab-nav-btn ${activeTab === "logistics" ? "active" : ""}`}
                onClick={() => setActiveTab("logistics")}
                role="tab"
                aria-selected={activeTab === "logistics"}
                aria-controls="logistics-panel"
                id="logistics-tab"
              >
                <span className="tab-icon">🚚</span>
                Service & Logistics
              </button>
              <button
                className={`tab-nav-btn ${activeTab === "demographics" ? "active" : ""}`}
                onClick={() => setActiveTab("demographics")}
                role="tab"
                aria-selected={activeTab === "demographics"}
                aria-controls="demographics-panel"
                id="demographics-tab"
              >
                <span className="tab-icon">👥</span>
                Demographics
              </button>
            </div>

            <div className="tab-content">
              {activeTab === "core" && (
                <div 
                  className="tab-panel active" 
                  id="core-panel"
                  role="tabpanel"
                  aria-labelledby="core-tab"
                >
                  <div className="panel-header">
                    <h3>💰 Core Business Metrics</h3>
                    <p>Essential customer engagement and value indicators</p>
                  </div>
                  <div className="fields-grid">
                    {renderField("Tenure Duration (months)", "Tenure", "number", null, 1, "Total months as customer")}
                    {renderField("Total Order Count", "OrderCount", "number", null, 1, "Lifetime orders placed")}
                    {renderField("Cashback Amount (₹)", "CashbackAmount", "number", null, 100, "Total cashback earned")}
                    {renderField("Order Value Hike (%)", "OrderAmountHikeFromlastYear", "number", null, 1, "Year-over-year order value change")}
                    {renderField("Coupons Used", "CouponUsed", "number", null, 1, "Total discount coupons redeemed")}
                    {renderField("Devices Registered", "NumberOfDeviceRegistered", "number", null, 1, "Number of registered devices")}
                    {renderField("Satisfaction Score", "SatisfactionScore", "number", null, 1, "Customer satisfaction rating (1-5)")}
                  </div>
                </div>
              )}

              {activeTab === "logistics" && (
                <div 
                  className="tab-panel active" 
                  id="logistics-panel"
                  role="tabpanel"
                  aria-labelledby="logistics-tab"
                >
                  <div className="panel-header">
                    <h3>🚚 Service & Logistics</h3>
                    <p>Customer interaction and service delivery metrics</p>
                  </div>
                  
                  {/* Complaint Field Only - Simple Layout */}
                  <div className="complaint-simple-container">
                    {renderField("Complaint Filed", "Complain", "select", null, null, "Recent service complaints")}
                  </div>

                  {/* Remaining fields in normal layout */}
                  <div className="fields-grid logistics-fields">
                    {renderField("Days Since Last Order", "DaySinceLastOrder", "number", null, 1, "Recency of last purchase")}
                    {renderField("Hours on App", "HourSpendOnApp", "number", null, 0.5, "Monthly app engagement hours")}
                    {renderField("Warehouse Distance (km)", "WarehouseToHome", "number", null, 1, "Distance to nearest warehouse")}
                    {renderField("Delivery Addresses", "NumberOfAddress", "number", null, 1, "Number of saved addresses")}
                    {renderField("Preferred Login Device", "PreferredLoginDevice", "select", [
                      "Mobile Phone", "Computer", "Phone", "Tablet"
                    ], null, "Primary access device")}
                    {renderField("Favorite Category", "PreferedOrderCat", "select", [
                      "Laptop & Accessory", "Mobile & Accessory", "Grocery", 
                      "Fashion", "Electronics", "Beauty", "Books"
                    ], null, "Most purchased category")}
                  </div>
                </div>
              )}

              {activeTab === "demographics" && (
                <div 
                  className="tab-panel active" 
                  id="demographics-panel"
                  role="tabpanel"
                  aria-labelledby="demographics-tab"
                >
                  <div className="panel-header">
                    <h3>👥 Customer Demographics</h3>
                    <p>Personal and geographic customer information</p>
                  </div>
                  <div className="fields-grid demographics-fields">
                    {/* First Row */}
                    <div className="demographics-row">
                      {renderField("Gender", "Gender", "select", ["Male", "Female", "Other"], null, "Customer gender")}
                      {renderField("Marital Status", "MaritalStatus", "select", ["Married", "Single", "Divorced", "Widowed"], null, "Relationship status")}
                    </div>
                    
                    {/* Second Row */}
                    <div className="demographics-row">
                      {renderField("Payment Method", "PreferredPaymentMode", "select", [
                        "Credit Card", "Debit Card", "UPI", "Net Banking", 
                        "Cash on Delivery", "E-Wallet"
                      ], null, "Preferred payment option")}
                      {renderField("City Tier", "CityTier", "select", [1, 2, 3], null, "City classification tier")}
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Action Buttons at Bottom */}
          <div className="action-buttons-bottom">
            <button 
              type="button"
              className="action-btn secondary" 
              onClick={onReset}
              disabled={loading}
            >
              <span className="btn-icon">🔄</span>
              Reset Form
            </button>
            <button 
              type="submit"
              className="action-btn primary" 
              disabled={loading || Object.keys(errors).length > 0}
              aria-live="polite"
            >
              {loading ? (
                <>
                  <div className="spinner" aria-hidden="true"></div>
                  Analyzing...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Run Analysis
                </>
              )}
            </button>
          </div>
        </div>
      </form>

      {/* Results Section */}
      {renderResults()}
    </div>
  );
}

export default IndividualAnalysis;
